# PIN Change Rate Limiting - pytest Test Suite

```python
"""
Test suite for PIN change rate limiting requirement.

Requirement: A customer shall change their card PIN at most 5 times
             per 24-hour rolling window.

Covers:
  - Happy path: up to 5 PIN changes succeed
  - Negative paths: exceeded limit, unauthorised, insufficient funds (fee),
    invalid current PIN, locked account, expired card, concurrent requests
"""

import pytest
from datetime import datetime, timedelta, timezone
from unittest.mock import MagicMock, patch, call
from freezegun import freeze_time

# ---------------------------------------------------------------------------
# Domain / application layer stubs
# Replace with your real imports, e.g.:
#   from banking.pin_service import PinService, PinChangeResult
#   from banking.exceptions import (
#       UnauthorisedException, ExceededPinChangeLimitException,
#       InsufficientFundsException, CardExpiredException, AccountLockedException
#   )
# ---------------------------------------------------------------------------

class UnauthorisedException(Exception):
    pass

class ExceededPinChangeLimitException(Exception):
    """Raised when the customer exceeds 5 PIN changes in 24 hours."""
    pass

class InsufficientFundsException(Exception):
    """Raised when a fee-bearing PIN change cannot be covered by the balance."""
    pass

class CardExpiredException(Exception):
    pass

class AccountLockedException(Exception):
    pass

class InvalidCurrentPinException(Exception):
    pass


class PinChangeResult:
    def __init__(self, success: bool, attempts_remaining: int):
        self.success = success
        self.attempts_remaining = attempts_remaining  # attempts left in window


PIN_CHANGE_LIMIT = 5
WINDOW_HOURS = 24
PIN_CHANGE_FEE = 0.00          # set > 0.00 if your domain charges a fee


# ---------------------------------------------------------------------------
# Fixtures
# ---------------------------------------------------------------------------

@pytest.fixture
def mock_account():
    account = MagicMock()
    account.account_id = "ACC-001"
    account.card_number = "4111111111111111"
    account.balance = 500.00
    account.is_locked = False
    account.card_expired = False
    account.current_pin_hash = "hashed_1234"
    return account


@pytest.fixture
def mock_pin_change_repository():
    """Tracks PIN change timestamps for an account."""
    repo = MagicMock()
    repo.count_changes_in_window.return_value = 0   # default: no prior changes
    repo.get_changes_in_window.return_value = []
    return repo


@pytest.fixture
def mock_auth_service():
    auth = MagicMock()
    auth.authenticate.return_value = True
    return auth


@pytest.fixture
def pin_service(mock_pin_change_repository, mock_auth_service):
    """
    Lightweight in-process PinService built from mocks.
    Replace with real service construction in your codebase.
    """
    from dataclasses import dataclass

    @dataclass
    class PinService:
        repo: object
        auth: object
        limit: int = PIN_CHANGE_LIMIT
        window_hours: int = WINDOW_HOURS
        fee: float = PIN_CHANGE_FEE

        def change_pin(
            self,
            account,
            current_pin: str,
            new_pin: str,
            token: str,
        ) -> PinChangeResult:
            # 1. Authorisation check
            if not self.auth.authenticate(account.account_id, token):
                raise UnauthorisedException("Invalid token or credentials.")

            # 2. Account state checks
            if account.is_locked:
                raise AccountLockedException("Account is locked.")
            if account.card_expired:
                raise CardExpiredException("Card has expired.")

            # 3. Validate current PIN
            if not self._verify_pin(account, current_pin):
                raise InvalidCurrentPinException("Current PIN is incorrect.")

            # 4. Rate-limit check (rolling 24-hour window)
            changes_in_window = self.repo.count_changes_in_window(
                account.account_id,
                window_hours=self.window_hours,
            )
            if changes_in_window >= self.limit:
                raise ExceededPinChangeLimitException(
                    f"PIN change limit of {self.limit} per {self.window_hours}h exceeded."
                )

            # 5. Fee check (if applicable)
            if self.fee > 0 and account.balance < self.fee:
                raise InsufficientFundsException(
                    f"Insufficient funds to cover PIN change fee of {self.fee}."
                )

            # 6. Persist change
            self.repo.record_change(account.account_id)
            account.balance -= self.fee

            attempts_remaining = self.limit - (changes_in_window + 1)
            return PinChangeResult(success=True, attempts_remaining=attempts_remaining)

        @staticmethod
        def _verify_pin(account, provided_pin: str) -> bool:
            import hashlib
            return account.current_pin_hash == f"hashed_{provided_pin}"

    return PinService(repo=mock_pin_change_repository, auth=mock_auth_service)


# ---------------------------------------------------------------------------
# Helper
# ---------------------------------------------------------------------------

def _set_prior_changes(mock_repo, count: int):
    """Simulate `count` PIN changes already recorded in the window."""
    mock_repo.count_changes_in_window.return_value = count


# ===========================================================================
# HAPPY PATH TESTS
# ===========================================================================

class TestPinChangeHappyPath:

    def test_first_pin_change_succeeds(
        self, pin_service, mock_account, mock_pin_change_repository
    ):
        """A customer with no prior changes can change their PIN."""
        _set_prior_changes(mock_pin_change_repository, 0)

        result = pin_service.change_pin(
            mock_account, current_pin="1234", new_pin="5678", token="valid-token"
        )

        assert result.success is True
        assert result.attempts_remaining == 4

    def test_fifth_pin_change_succeeds(
        self, pin_service, mock_account, mock_pin_change_repository
    ):
        """The 5th PIN change within a 24-hour window is still permitted."""
        _set_prior_changes(mock_pin_change_repository, 4)

        result = pin_service.change_pin(
            mock_account, current_pin="1234", new_pin="9999", token="valid-token"
        )

        assert result.success is True
        assert result.attempts_remaining == 0

    def test_each_successful_change_records_to_repository(
        self, pin_service, mock_account, mock_pin_change_repository
    ):
        """Every successful PIN change must be persisted."""
        _set_prior_changes(mock_pin_change_repository, 2)

        pin_service.change_pin(
            mock_account, current_pin="1234", new_pin="4321", token="valid-token"
        )

        mock_pin_change_repository.record_change.assert_called_once_with(
            mock_account.account_id
        )

    @freeze_time("2024-01-15 10:00:00")
    def test_window_resets_after_24_hours(
        self, pin_service, mock_account, mock_pin_change_repository
    ):
        """
        After the 24-hour window rolls over, the customer can change their
        PIN again even if they reached the limit in the previous window.
        """
        # Simulate: 5 changes were made but ALL are now > 24 hours old,
        # so the rolling window count resets to 0.
        _set_prior_changes(mock_pin_change_repository, 0)

        result = pin_service.change_pin(
            mock_account, current_pin="1234", new_pin="1111", token="valid-token"
        )

        assert result.success is True

    def test_attempts_remaining_decrements_correctly(
        self, pin_service, mock_account, mock_pin_change_repository
    ):
        """Verify attempts_remaining decrements from 4 → 0 across 5 calls."""
        expected_remaining = [4, 3, 2, 1, 0]

        for idx, expected in enumerate(expected_remaining):
            _set_prior_changes(mock_pin_change_repository, idx)
            result = pin_service.change_pin(
                mock_account, current_pin="1234", new_pin="0000", token="valid-token"
            )
            assert result.attempts_remaining == expected, (
                f"After change #{idx + 1} expected {expected} remaining, "
                f"got {result.attempts_remaining}"
            )


