# EXCEEDED LIMIT TESTS
# ===========================================================================

class TestPinChangeLimitExceeded:

    def test_sixth_change_raises_exceeded_limit_exception(
        self, pin_service, mock_account, mock_pin_change_repository
    ):
        """The 6th PIN change attempt within 24 hours must be rejected."""
        _set_prior_changes(mock_pin_change_repository, 5)

        with pytest.raises(ExceededPinChangeLimitException):
            pin_service.change_pin(
                mock_account, current_pin="1234", new_pin="6666", token="valid-token"
            )

    def test_exceeded_limit_does_not_record_change(
        self, pin_service, mock_account, mock_pin_change_repository
    ):
        """A rejected PIN change must NOT be written to the repository."""
        _set_prior_changes(mock_pin_change_repository, 5)

        with pytest.raises(ExceededPinChangeLimitException):
            pin_service.change_pin(
                mock_account, current_pin="1234", new_pin="7777", token="valid-token"
            )

        mock_pin_change_repository.record_change.assert_not_called()

    def test_tenth_attempt_still_raises_exceeded_limit(
        self, pin_service, mock_account, mock_pin_change_repository
    ):
        """Repeated attempts beyond the limit continue to be rejected."""
        _set_prior_changes(mock_pin_change_repository, 10)

        with pytest.raises(ExceededPinChangeLimitException):
            pin_service.change_pin(
                mock_account, current_pin="1234", new_pin="8888", token="valid-token"
            )

    def test_exceeded_limit_error_message_contains_limit_info(
        self, pin_service, mock_account, mock_pin_change_repository
    ):
        """Exception message should surface the limit and window to the caller."""
        _set_prior_changes(mock_pin_change_repository, 5)

        with pytest.raises(ExceededPinChangeLimitException) as exc_info:
            pin_service.change_pin(
                mock_account, current_pin="1234", new_pin="2222", token="valid-token"
            )

        assert "5" in str(exc_info.value)
        assert "24" in str(exc_info.value)

    @pytest.mark.parametrize("prior_changes", [5, 6, 7, 100])
    def test_limit_exceeded_for_various_over_limit_counts(
        self, pin_service, mock_account, mock_pin_change_repository, prior_changes
    ):
        """Parameterised: any value >= 5 prior changes must trigger the limit."""
        _set_prior_changes(mock_pin_change_repository, prior_changes)

        with pytest.raises(ExceededPinChangeLimitException):
            pin_service.change_pin(
                mock_account, current_pin="1234", new_pin="3333", token="valid-token"
            )


