class TestPinChangeUnauthorised:

    def test_invalid_token_raises_unauthorised(
        self, pin_service, mock_account, mock_auth_service
    ):
        """A request with an invalid auth token must be rejected."""
        mock_auth_service.authenticate.return_value = False

        with pytest.raises(UnauthorisedException):
            pin_service.change_pin(
                mock_account, current_pin="1234", new_pin="5678", token="bad-token"
            )

    def test_unauthorised_does_not_record_change(
        self, pin_service, mock_account, mock_auth_service, mock_pin_change_repository
    ):
        """An unauthorised request must not write to the repository."""
        mock_auth_service.authenticate.return_value = False

        with pytest.raises(UnauthorisedException):
            pin_service.change_pin(
                mock_account, current_pin="1234", new_pin="5678", token="bad-token"
            )

        mock_pin_change_repository.record_change.assert_not_called()

    def test_wrong_current_pin_raises_invalid_pin(
        self, pin_service, mock_account
    ):
        """Providing an incorrect current PIN must raise InvalidCurrentPinException."""
        with pytest.raises(InvalidCurrentPinException):
            pin_service.change_pin(
                mock_account,
                current_pin="wrong_pin",
                new_pin="5678",
                token="valid-token",
            )

    def test_wrong_current_pin_does_not_record_change(
        self, pin_service, mock_account, mock_pin_change_repository
    ):
        """A wrong current PIN attempt must not consume a slot in the rate limit."""
        with pytest.raises(InvalidCurrentPinException):
            pin_service.change_pin(
                mock_account,
                current_pin="wrong_pin",
                new_pin="5678",
                token="valid-token",
            )

        mock_pin_change_repository.record_change.assert_not_called()

    def test_locked_account_raises_account_locked(
        self, pin_service, mock_account
    ):
        """A locked account must not be allowed to change its PIN."""
        mock_account.is_locked = True

        with pytest.raises(AccountLockedException):
            pin_service.change_pin(
                mock_account, current_pin="1234", new_pin="5678", token="valid-token"
            )

    def test_locked_account_does_not_record_change(
        self, pin_service, mock_account, mock_pin_change_repository
    ):
        mock_account.is_locked = True

        with pytest.raises(AccountLockedException):
            pin_service.change_pin(
                mock_account, current_pin="1234", new_pin="5678", token="valid-token"
            )

        mock_pin_change_repository.record_change.assert_not_called()

    def test_expired_card_raises_card_expired(
        self, pin_service, mock_account
    ):
        """An expired card must not permit PIN changes."""
        mock_account.card_expired = True

        with pytest.raises(CardExpiredException):
            pin_service.change_pin(
                mock_account, current_pin="1234", new_pin="5678", token="valid-token"
            )

    def test_expired_card_does_not_record_change(
        self, pin_service, mock_account, mock_pin_change_repository
    ):
        mock_account.card_expired = True

        with pytest.raises(CardExpiredException):
            pin_service.change_pin(
                mock_account, current_pin="1234", new_pin="5678", token="valid-token"
            )

        mock_pin_change_repository.record_change.assert_not_called()


