class TestPinChangeInsufficientFunds:

    @pytest.fixture
    def fee_pin_service(self, mock_pin_change_repository, mock_auth_service):
        """PinService variant that charges a £1.50 fee per PIN change."""
        from dataclasses import dataclass

        @dataclass
        class FeePinService:
            repo: object
            auth: object
            limit: int = PIN_CHANGE_LIMIT
            window_hours: int = WINDOW_HOURS
            fee: float = 1.50  # fee-bearing variant

            def change_pin(self, account, current_pin, new_pin, token):
                if not self.auth.authenticate(account.account_id, token):
                    raise UnauthorisedException("Invalid token.")
                if account.is_locked:
                    raise AccountLockedException("Account locked.")
                if account.card_expired:
                    raise CardExpiredException("Card expired.")
                if not (account.current_pin_hash == f"hashed_{current_pin}"):
                    raise InvalidCurrentPinException("Wrong current PIN.")

                changes_in_window = self.repo.count_changes_in_window(
                    account.account_id, window_hours=self.window_hours
                )
                if changes_in_window >= self.limit:
                    raise ExceededPinChangeLimitException("Limit exceeded.")

                if account.balance < self.fee:
                    raise InsufficientFundsException(
                        f"Balance {account.balance} < fee {self.fee}."
                    )

                self.repo.record_change(account.account_id)
                account.balance -= self.fee
                return PinChangeResult(
                    success=True,
                    attempts_remaining=self.limit - (changes_in_window + 1),
                )

        return FeePinService(
            repo=mock_pin_change_repository, auth=mock_auth_service
        )

    def test_zero_balance_raises_insufficient_funds(
        self, fee_pin_service, mock_account, mock_pin_change_repository
    ):
        """Balance of £0.00 cannot cover the fee; must raise InsufficientFundsException."""
        mock_account.balance = 0.00
        _set_prior_changes(mock_pin_change_repository, 0)

        with pytest.raises(InsufficientFundsException):
            fee_pin_service.change_pin(
                mock_account, current_pin="1234", new_pin="5678", token="valid-token"
            )

    def test_balance_below_fee_raises_insufficient_funds(
        self, fee_pin_service, mock_account, mock_pin_change_repository
    ):
        """Balance less than fee must raise InsufficientFundsException."""
        mock_account.balance = 1.00   # fee is £1.50
        _set_prior_changes(mock_pin_change_repository, 0)

        with pytest.raises(InsufficientFundsException):
            fee_pin_service.change_pin(
                mock_account, current_pin="1234", new_pin="5678", token="valid-token"
            )

    def test_insufficient_funds_does_not_record_change(
        self, fee_pin_service, mock_account, mock_pin_change_repository
    ):
        """A rejected fee-related request must not consume a rate-limit slot."""
        mock_account.balance = 0.00
        _set_prior_changes(mock_pin_change_repository, 0)

        with pytest.raises(InsufficientFundsException):
            fee_pin_service.change_pin(
                mock_account, current_pin="1234", new_pin="5678", token="valid-token"
            )

        mock_pin_change_repository.record_change.assert_not_called()

    def test_sufficient_balance_deducts_fee(
        self, fee_pin_service, mock_account, mock_pin_change_repository
    ):
        """When balance covers the fee, it must be deducted after a successful change."""
        mock_account.balance = 50.00
        _set_prior_changes(mock_pin_change_repository, 0)

        fee_pin_service.change_pin(
            mock_account, current_pin="1234", new_pin="5678", token="valid-token"
        )

        assert mock_account.balance == pytest.approx(48.50)

    def test_exact_fee_balance_succeeds(
        self, fee_pin_service, mock_account, mock_pin_change_repository
    ):
        """Balance exactly equal to the fee must succeed (boundary condition)."""
        mock_account.balance = 1.50
        _set_prior_changes(mock_pin_change_repository, 0)

        result = fee_pin_service.change_pin(
            mock_account, current_pin="1234", new_pin="5678", token="valid-token"
        )

        assert result.success is True
        assert mock_account.balance == pytest.approx(0.00)


