class TestPinChangeBoundaryConditions:

    @pytest.mark.parametrize("prior_changes,should_succeed", [
        (0, True),
        (1, True),
        (2, True),
        (3, True),
        (4, True),   # exactly at limit - 1: allowed
        (5, False),  # at limit: blocked
        (6, False),  # over limit: blocked
    ])
    def test_boundary_around_limit(
        self,
        pin_service,
        mock_account,
        mock_pin_change_repository,
        prior_changes,
        should_succeed,
    ):
        """Exhaustive boundary test around the 5-change limit."""
        _set_prior_changes(mock_pin_change_repository, prior_changes)

        if should_succeed:
            result = pin_service.change_pin(
                mock_account, current_pin="1234", new_pin="9999", token="valid-token"
            )
            assert result.success is True
        else:
            with pytest.raises(ExceededPinChangeLimitException):
                pin_service.change_pin(
                    mock_account,
                    current_pin="1234",
                    new_pin="9999",
                    token="valid-token",
                )

    @freeze_time("2024-06-01 23:59:59")
    def test_change_at_window_boundary_start(
        self, pin_service, mock_account, mock_pin_change_repository
    ):
        """PIN change just before the 24-hour window rolls over should work."""
        _set_prior_changes(mock_pin_change_repository, 0)

        result = pin_service.change_pin(
            mock_account, current_pin="1234", new_pin="1111", token="valid-token"
        )

        assert result.success is True

    def test_repository_queried_with_correct_window(
        self, pin_service, mock_account, mock_pin_change_repository
    ):
        """The repository must be queried with exactly a 24-hour window."""
        _set_prior_changes(mock_pin_change_repository, 0)

        pin_service.change_pin(
            mock_account, current_pin="1234", new_pin="5678", token="valid-token"
        )

        mock_pin_change_repository.count_changes_in_window.assert_called_once_with(
            mock_account.account_id, window_hours=24
        )

    def test_new_pin_same_as_current_is_allowed_by_service_layer(
        self, pin_service, mock_account, mock_pin_change_repository
    ):
        """
        Business rule: the service layer does not enforce PIN uniqueness —
        that is a separate validator's concern.  If uniqueness is NOT
        required, this test ensures no false rejection occurs.
        (Adjust or delete if your domain does enforce it.)
        """
        _set_prior_changes(mock_pin_change_repository, 0)

        result = pin_service.change_pin(
            mock_account, current_pin="1234", new_pin="1234", token="valid-token"
        )

        assert result.success is True


