class TestPinChangeConcurrency:

    def test_concurrent_requests_cannot_exceed_limit(
        self, mock_account, mock_pin_change_repository, mock_auth_service
    ):
        """
        Simulate two requests arriving simultaneously when 4 changes have
        already been made.  Only one should succeed; the second must be
        rejected.  (In production this would be enforced via a DB-level
        compare-and-swap or pessimistic lock.)
        """
        call_count = 0

        def count_side_effect(account_id, window_hours):
            nonlocal call_count
            # Both concurrent callers see the same pre-commit state (4).
            # The application layer relies on the DB to serialise the write.
            return 4

        mock_pin_change_repository.count_changes_in_window.side_effect = (
            count_side_effect
        )

        from dataclasses import dataclass

        @dataclass
        class AtomicPinService:
            repo: object
            auth: object
            limit: int = PIN_CHANGE_LIMIT
            window_hours: int = WINDOW_HOURS
            fee: float = 0.00
            _committed: int = 0   # simulates DB atomic counter

            def change_pin(self, account, current_pin, new_pin, token):
                if not self.auth.authenticate(account.account_id, token):
                    raise UnauthorisedException()
                if not (account.current_pin_hash == f"hashed_{current_pin}"):
                    raise InvalidCurrentPinException()

                # Simulated DB-level atomic increment with limit check
                if self._committed >= self.limit:
                    raise ExceededPinChangeLimitException("Limit exceeded.")
                self._committed += 1
                self.repo.record_change(account.account_id)
                return PinChangeResult(
                    success=True,
                    attempts_remaining=self.limit - self._committed,
                )

        svc = AtomicPinService(repo=mock_pin_change_repository, auth=mock_auth_service)
        svc._committed = 4  # already 4 changes recorded atomically

        # First concurrent request — should succeed
        result = svc.change_pin(
            mock_account, current_pin="1234", new_pin="5678", token="valid-token"
        )
        assert result.success is True

        # Second concurrent request — must be rejected
        with pytest.raises(ExceededPinChangeLimitException):
            svc.change_pin(
                mock_account, current_pin="1234", new_pin="9999", token="valid-token"
            )

        # Only one successful record_change call
        assert mock_pin_change_repository.record_change.call_count == 1
